{
  "id": "module_rainy_town_001",
  "version": "1.0",
  "world_id": "quickstart_rainy_town",
  "name": "雨镇失踪案",
  "player_count_min": 2,
  "player_count_max": 4,
  "duration_minutes": 90,
  "opening_hook": "连日暴雨中，镇上又有一名少年失踪。镇民互助会通过茶馆老板李姐，秘密邀请外来调查者介入。你们抵达雨镇时，看见青石桥下水流湍急，桥头贴着一张泛黄的寻人启事，落款日期是三天前。一个披着蓑衣的女人匆匆塞给你们一封信，低声道：‘陈家老宅的地下，藏着一切。’",
  "core_secret": "雨灵是百年前一场特大水灾中死去的村民执念聚合体，其源头位于陈家老宅地下室一口被铁锁井盖封印的‘水眼’。水眼连接着地下暗河，一旦被破坏，所有亡魂怨念将爆发，使雨镇变成真正的鬼镇。雨灵会模仿失踪者的声音引诱生人靠近水眼，意图解除封印。",
  "major_conflict": "陈家族长（陈伯）深知水眼的秘密，多年来通过《避雨经》和禁忌勉强压制雨灵，但他也暗中利用雨灵的力量排除异己。外乡人‘老吴’自称是民俗学家，实则觊觎水眼的能量，试图骗取《避雨经》的真本并破坏封印。调查者必须在阻止雨灵作祟的同时，在陈伯的保守立场与老吴的激进野心之间做出抉择，并防止误触禁忌导致灾难。",
  "required_npcs": [
    {
      "name": "陈伯",
      "role": "陈家族长",
      "description": "六十多岁，寡言，眼神阴郁。掌管陈家老宅和《避雨经》真本，表面上配合调查，实则处处设限。知道水眼的全部真相，但不愿外人插手。"
    },
    {
      "name": "李姐",
      "role": "雨珠茶楼老板",
      "description": "四十岁，精明圆滑，消息灵通。她信任陈伯，但更担心镇子的安危。愿意在可控范围内帮助调查者，提供线索和庇护。"
    },
    {
      "name": "王婶",
      "role": "失踪少年的母亲",
      "description": "三十八岁，憔悴，精神近崩溃。坚信儿子还活着，每晚冒雨在青石桥附近呼唤儿子的名字（触犯禁忌）。她无意中记下了雨灵模仿的声音特点，但自己并未意识到。"
    },
    {
      "name": "老吴",
      "role": "神秘外乡人",
      "description": "五十岁左右，自称民俗学者，实则道术小偷。对水眼和《避雨经》极感兴趣，暗中收集破除封印的材料。表面友善，承诺‘解决镇子问题’，实则另有目的。"
    }
  ],
  "key_locations": [
    "陈家老宅（三层木楼，地下室铁锁井盖下方即水眼）",
    "镇档案馆（存放历年失踪案卷宗，其中一份百年前船难记录是关键线索）",
    "雨珠茶楼（深夜营业，李姐提供情报和《避雨经》残页）",
    "古井广场（中央古井是水眼泄压口，雨夜渗出红水时表明雨灵活动加剧）"
  ],
  "key_clues": [
    "镇档案馆中一份民国十年的船难记录：当日暴雨，一船三十余名村民全部溺亡，尸体被冲入地下暗河。记录末尾用红笔批注‘水眼始，雨灵生’字样。",
    "陈家老宅地下室铁锁井盖上刻有八卦纹路，中央刻‘水眼’二字，边缘有新鲜香灰和纸钱残烬，表明陈伯近日仍在秘密祭祀。",
    "雨珠茶楼李姐私下提供的《避雨经》残页，上写‘雨灵乃死者怨念所聚，镇于水眼之下，非族长正音不可诵’；背面有用铅笔写的字：‘族长每日丑时在地下室诵经——李偷记’。"
  ],
  "threat_clock_id": "threat_rain_infestation",
  "endings": [
    {
      "type": "good",
      "description": "调查者成功从陈伯处取得《避雨经》正确念法，并在水眼旁完成封印仪式。雨灵被重新镇压，镇子上的暴雨逐渐停止，少年失踪案告破（少年实际被困在旧宅地下室水眼附近，被救出）。陈伯公开承认错误，同意销毁水眼相关庇护，雨镇重归平静。"
    },
    {
      "type": "partial",
      "description": "调查者未能取得完整经文，只得借助残页和自身知识勉强封印水眼。雨灵活动暂时平息，雨势减弱，但每至深夜仍能听见水眼传来的低语。失踪少年未能找回（已溺亡），但镇子避免了全面爆发。陈伯与老吴各自受到警告，但隐患长存。"
    },
    {
      "type": "bad",
      "description": "调查者误信老吴，或不慎打开铁锁井盖，或念错《避雨经》激发怨念。水眼彻底爆发，雨灵暴动：百年前亡魂的怨念实体化，席卷全镇。所有居民或失踪或发狂，雨镇变成一座被浓雾和诅咒笼罩的鬼镇，调查者若幸存必须以最残酷的方式逃离。"
    }
  ],
  "ai_do_not_change": [
    "雨灵是百年前因水灾死去的村民执念聚合体，其源头位于陈家老宅地下室的水眼。",
    "陈家老宅地下室的铁锁井盖封印着水眼，破坏它会导致全镇灵异暴动。",
    "《避雨经》正确念法只有陈家族长知晓，念错会激怒雨灵。",
    "古井广场的古井是水眼的泄压口，雨夜渗红水表明雨灵活动加剧。"
  ],
  "ai_freedom_level": "medium"
}
